{"command": "cd /tmp/sv-9e913e0697bf4f6c957f963d1a9ea066/advanced-multi-complexity && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (pname, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]} | {c[1]} | {c[2]} | {c[3]} -> {c[4]}')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]} | {u[1]} | {u[2]} | {u[3]}')
"", "description": "Compare baseline vs post-conversion", "initial_wait": 10}
